import { useLocation, useNavigate } from "react-router-dom";

export default function JoinCreateSuccess() {
  const navigate = useNavigate();
  const { state } = useLocation();

  const isCreate = state?.type === "create";
  const title = state?.title || "your home";
  const code = state?.code || "ABCD12";

  return (
    <main className="min-h-screen bg-[#eadbc9] flex items-center justify-center px-6">
      <section className="w-full max-w-[1200px] flex flex-col items-center text-center -mt-12">
        <h1
          className="text-[#6b4b3e] font-semibold tracking-[0.01em] mb-8"
          style={{
            fontSize: "clamp(3rem, 5vw, 4.8rem)",
            lineHeight: 1,
            fontFamily: '"Trebuchet MS", "Segoe UI", sans-serif',
          }}
        >
          success!
        </h1>

        <p className="text-[#6b4b3e] text-[1.5rem] mb-3">
          {isCreate ? `you created ${title}` : "you joined a home"}
        </p>

        {isCreate ? (
          <p className="text-[#7c695f] text-[1.25rem] mb-10">
            share code <span className="font-semibold text-[#5a3e36]">{code}</span>
          </p>
        ) : (
          <p className="text-[#7c695f] text-[1.25rem] mb-10">
            you are all set to start assigning chores
          </p>
        )}

        <button
          onClick={() => navigate("/dashboard")}
          className="w-[340px] h-[78px] rounded-[22px] bg-[#aab095] text-[#43332c] text-[2.15rem] leading-none shadow-[inset_0_0_0_1px_rgba(90,62,54,0.28)] hover:brightness-[0.98] active:translate-y-[1px] transition"
          style={{ fontFamily: '"Trebuchet MS", "Segoe UI", sans-serif' }}
        >
          continue
        </button>
      </section>
    </main>
  );
}
